const { chromium } = require('playwright');
(async () => {
    const browser = await chromium.launch();
    const page = await browser.newPage();
    await page.setViewportSize({ width: 1280, height: 800 });
    await page.goto('file:///C:/Users/PC/Documents/AntiGravity/Projects/SwimLanes/Swimlane_App.html');
    await page.waitForTimeout(1000);
    // dismiss onboarding if present
    const has = await page.evaluate(() => document.getElementById('onboarding-overlay')?.classList.contains('is-open'));
    if (has) await page.click('[data-action=\"startFresh\"]');
    await page.waitForTimeout(500);
    await page.screenshot({ path: 'tools/laptop-preview.png', fullPage: false });
    await browser.close();
    console.log('done');
})();
"

