    await page.goto('file:///C:/Users/PC/Documents/AntiGravity/Projects/SwimLanes/Swimlane_App.html');
    await page.waitForTimeout(1000);
    const has = await page.evaluate(() => document.getElementById('onboarding-overlay')?.classList.contains('is-open'));
    if (has) await page.click('[data-action=\"startFresh\"]');
    await page.waitForTimeout(600);
    await page.screenshot({ path: 'tools/laptop-preview.png' });
    await browser.close();
    console.log('done');
})();
"

